import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as c,c as n,a as e,b as a,d as i,e as s}from"./app-fd10997f.js";const l={},p=s('<p>오토 스케일링(Auto Scaling)은 클라우드 컴퓨팅 환경에서 필요에 따라 서비스를 빠르게 확장하거나<br> 서버 자원을 모니터링하여 서버 사이즈를 자동으로 조절하는 서비스를 말한다.</p><p>오토 스케일링의 방법에는 크케 스케일 업과 스케일 아웃이 있다.</p><h2 id="스케일-업-scale-up" tabindex="-1"><a class="header-anchor" href="#스케일-업-scale-up" aria-hidden="true">#</a> 스케일 업 (Scale Up)</h2><p>램이 1기가인 컴퓨터를 16기가로 교체하는 것처럼 하드웨어의 성능을 올리는 것을 스케일 업이라고한다.</p><h2 id="스케일-아웃-scale-out" tabindex="-1"><a class="header-anchor" href="#스케일-아웃-scale-out" aria-hidden="true">#</a> 스케일 아웃 (Scale Out)</h2><p>이번에 적용해보려는게 스케일 아웃이다. 스케일 아웃은 규모를 늘리는 것이다.</p><p>아마존 프리티어로 ec2 t2.micro의 무료사용시간이 한달에 750시간인 걸 이용해<br> cpu의 사용률이 80%가 넘으면 서버 인스턴스를 자동으로 생성하게 설정할 것이다.</p><p>참고로 ec2 무료사용시간은 인스턴스가 생성된 갯수 기준으로 비례로 차감된다.<br> 즉, t2.micro를 2개 만들어서 사용하면 총 무료사용시간은 350시간이다.</p><p>프로젝트에서 단일 인스턴스를 사용해왔는데 이번 프로젝트에서 무중단 서비스를 해보기위해<br> 사용자는 없지만 오토스케일링을 설정해놓고 서버 부하가 늘어날 것을 미리 대비해보려고 한다.</p><p>오토스케일링 설정을 해보면서 다음과 같이 설정 과정을 시리즈로 정리할 예정이다.</p><ol><li>오토스케일링 설정</li><li>그라파나로 로그 모니터링</li><li>부하테스트</li></ol><h2 id="참고-링크" tabindex="-1"><a class="header-anchor" href="#참고-링크" aria-hidden="true">#</a> 참고 링크</h2>',12),d={href:"https://inpa.tistory.com/entry/AWS-%F0%9F%93%9A-EC2-%EC%98%A4%ED%86%A0-%EC%8A%A4%EC%BC%80%EC%9D%BC%EB%A7%81-ELB-%EB%A1%9C%EB%93%9C-%EB%B0%B8%EB%9F%B0%EC%84%9C-%EA%B0%9C%EB%85%90-%EA%B5%AC%EC%B6%95-%EC%84%B8%ED%8C%85-%F0%9F%92%AF-%EC%A0%95%EB%A6%AC",target:"_blank",rel:"noopener noreferrer"};function h(E,B){const r=o("ExternalLinkIcon");return c(),n("div",null,[p,e("p",null,[a("📌 "),e("a",d,[a("https://inpa.tistory.com/entry/AWS-📚-EC2-오토-스케일링-ELB-로드-밸런서-개념-구축-세팅-💯-정리"),i(r)])])])}const u=t(l,[["render",h],["__file","introduce.html.vue"]]);export{u as default};
